INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('d83ac8d9-5b2a-4d19-a096-b2b243f3148e', NULL, 'medium', NULL, NULL, '{"en": "What is the next number: 1, 2, 4, 7, 11, 16, ?", "kz": "Келесі сан: 1, 2, 4, 7, 11, 16, ?"}', '[{"en": "21", "kz": "21"}, {"en": "22", "kz": "22"}, {"en": "23", "kz": "23"}, {"en": "28", "kz": "28"}]', 1, '🔢', NULL, 60, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('dbbaf8f4-b071-4a0a-b763-9cf36d471cde', NULL, 'medium', NULL, NULL, '{"en": "Two towns are 100 km apart. Two trains leave toward each other at 50 km/h each. A bird flies 75 km/h between them until they meet. How far does the bird fly?", "kz": "Екі қала 100 км қашықтықта. Екі пойыз бір-біріне қарай 50 км/сағ жылдамдықпен шығады. Құс олардың арасында кездескенше 75 км/сағ ұшады. Құс қанша км ұшады?"}', '[{"en": "50 km", "kz": "50 км"}, {"en": "75 km", "kz": "75 км"}, {"en": "100 km", "kz": "100 км"}, {"en": "150 km", "kz": "150 км"}]', 1, '🚆', NULL, 60, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('10075c11-6eaf-48cd-8e60-153f84682918', NULL, 'medium', NULL, NULL, '{"en": "What is the next number: 3, 7, 15, 31, 63, ?", "kz": "Келесі сан: 3, 7, 15, 31, 63, ?"}', '[{"en": "95", "kz": "95"}, {"en": "126", "kz": "126"}, {"en": "127", "kz": "127"}, {"en": "128", "kz": "128"}]', 2, '🔢', NULL, 60, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('2ed22f6c-b49c-4227-a739-1706cfdffede', NULL, 'medium', NULL, NULL, '{"en": "In a race, you overtake the runner in 2nd place. What position are you in now?", "kz": "Жарыста сіз 2-орындағы жүгірушіні басып озасыз. Енді қай орындасыз?"}', '[{"en": "1st", "kz": "1-ші"}, {"en": "2nd", "kz": "2-ші"}, {"en": "3rd", "kz": "3-ші"}, {"en": "Last", "kz": "Соңғы"}]', 1, '🏃', NULL, 60, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('c29e31fe-7af3-4d68-acbd-396dc21768ae', NULL, 'medium', NULL, NULL, '{"en": "How many times can you subtract 5 from 25?", "kz": "25-тен 5-ті неше рет азайтуға болады?"}', '[{"en": "Once", "kz": "Бір рет"}, {"en": "4 times", "kz": "4 рет"}, {"en": "5 times", "kz": "5 рет"}, {"en": "Infinite", "kz": "Шексіз"}]', 0, '➖', NULL, 60, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('a0366ee6-8126-4989-a626-0323413fecd4', NULL, 'medium', NULL, NULL, '{"en": "Roll two dice. What is the probability the sum equals 7?", "kz": "Екі сүйек лақтырылды. Қосындысы 7-ге тең болу ықтималдығы қанша?"}', '[{"en": "1/6", "kz": "1/6"}, {"en": "1/8", "kz": "1/8"}, {"en": "5/36", "kz": "5/36"}, {"en": "1/12", "kz": "1/12"}]', 0, '🎲', NULL, 60, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('f7ad4003-d8de-4ca6-9437-6d29d418b80b', NULL, 'medium', NULL, NULL, '{"en": "In the puzzle SEND + MORE = MONEY, what digit does M represent?", "kz": "SEND + MORE = MONEY жұмбағында M қай цифрды білдіреді?"}', '[{"en": "0", "kz": "0"}, {"en": "1", "kz": "1"}, {"en": "8", "kz": "8"}, {"en": "9", "kz": "9"}]', 1, '💰', NULL, 60, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('d4883cc3-7cf2-4733-b8fb-f0b1b10b3fd9', NULL, 'medium', NULL, NULL, '{"en": "What is the next number: 2, 12, 36, 80, 150, ?", "kz": "Келесі сан: 2, 12, 36, 80, 150, ?"}', '[{"en": "210", "kz": "210"}, {"en": "240", "kz": "240"}, {"en": "252", "kz": "252"}, {"en": "300", "kz": "300"}]', 2, '🔢', NULL, 60, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('93d42df3-41b1-4b08-9bb6-85c671529841', NULL, 'medium', NULL, NULL, '{"en": "A is the father of B, but B is not the son of A. How is this possible?", "kz": "A — B-нің әкесі, бірақ B — A-ның ұлы емес. Бұл қалай мүмкін?"}', '[{"en": "B is a daughter", "kz": "B — қыз"}, {"en": "A is lying", "kz": "A өтірік айтып тұр"}, {"en": "It is impossible", "kz": "Мүмкін емес"}, {"en": "B is adopted", "kz": "B — асырап алынған"}]', 0, '👨‍👧', NULL, 60, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('9f03da58-28a9-40de-bda6-4ba06f64d493', NULL, 'hard', NULL, NULL, '{"en": "On an island, knights always tell the truth and knaves always lie. You meet A and B. A says: ''We are both knaves.'' What are A and B?", "kz": "Аралда рыцарьлар әрқашан шындықты, ал жалғаншылар әрқашан өтірік айтады. Сіз A мен B-ні кездестірдіңіз. A: «Екеуміз де жалғаншымыз» дейді. A мен B кім?"}', '[{"en": "A is a knight, B is a knave", "kz": "A — рыцарь, B — жалғаншы"}, {"en": "A is a knave, B is a knight", "kz": "A — жалғаншы, B — рыцарь"}, {"en": "Both are knaves", "kz": "Екеуі де жалғаншы"}, {"en": "Both are knights", "kz": "Екеуі де рыцарь"}]', 1, '🛡️', NULL, 300, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('26bc753f-d767-4972-9933-ae4c8079591f', NULL, 'hard', NULL, NULL, '{"en": "Three boxes are labeled ''Apples'', ''Oranges'', and ''Apples & Oranges''. Every label is wrong. Drawing one fruit from a single box, which box lets you correctly relabel all three?", "kz": "Үш жәшік «Алма», «Апельсин» және «Алма мен Апельсин» деп белгіленген. Барлық белгі қате. Бір жәшіктен бір жеміс алып, үшеуін де дұрыс белгілеу үшін қай жәшіктен алу керек?"}', '[{"en": "The one labeled ''Apples''", "kz": "«Алма» деп белгіленгені"}, {"en": "The one labeled ''Oranges''", "kz": "«Апельсин» деп белгіленгені"}, {"en": "The one labeled ''Apples & Oranges''", "kz": "«Алма мен Апельсин» деп белгіленгені"}, {"en": "Any box works", "kz": "Кез келген жәшік жарайды"}]', 2, '📦', NULL, 300, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('4822fd52-4ab7-484c-9d31-641a86fde5c0', NULL, 'hard', NULL, NULL, '{"en": "A disease affects 1 in 10,000 people. A test is 99% accurate. You test positive. Roughly what is the probability you actually have the disease?", "kz": "Ауру 10 000 адамның 1-іне әсер етеді. Тест 99% дәл. Нәтижеңіз оң шықты. Сізде шынымен ауру болу ықтималдығы шамамен қанша?"}', '[{"en": "About 99%", "kz": "Шамамен 99%"}, {"en": "About 90%", "kz": "Шамамен 90%"}, {"en": "About 50%", "kz": "Шамамен 50%"}, {"en": "About 1%", "kz": "Шамамен 1%"}]', 3, '🧪', NULL, 300, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('a52e2767-5dcd-43a4-9694-c953577405e1', NULL, 'hard', NULL, NULL, '{"en": "Outside a sealed room are 3 switches; one turns on a bulb inside. You may flip switches freely but can enter the room only once. How do you find the right switch?", "kz": "Жабық бөлменің сыртында 3 қосқыш бар; біреуі іштегі шамды қосады. Қосқыштарды қалағаныңызша баса аласыз, бірақ бөлмеге тек бір рет кіресіз. Дұрыс қосқышты қалай табасыз?"}', '[{"en": "It is impossible with one entry", "kz": "Бір кіріспен мүмкін емес"}, {"en": "Turn one on a while then off; turn another on; enter — use the bulb''s light and warmth", "kz": "Біреуін біраз қосып өшіріңіз; екіншісін қосыңыз; кіріп — шамның жарығы мен жылуын пайдаланыңыз"}, {"en": "Switch all three on, then enter", "kz": "Үшеуін де қосып, кіріңіз"}, {"en": "Ask someone inside", "kz": "Іштегі біреуден сұраңыз"}]', 1, '💡', NULL, 300, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('35e6c16b-f68f-4766-9be7-721d12185736', NULL, 'hard', NULL, NULL, '{"en": "In a room of just 23 people, the probability that at least two share the same birthday is closest to:", "kz": "Бар болғаны 23 адам бар бөлмеде кемінде екеуінің туған күні бірдей болу ықтималдығы неге жақын?"}', '[{"en": "About 6%", "kz": "Шамамен 6%"}, {"en": "About 23%", "kz": "Шамамен 23%"}, {"en": "About 50%", "kz": "Шамамен 50%"}, {"en": "About 99%", "kz": "Шамамен 99%"}]', 2, '🎂', NULL, 300, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('44934b87-a48b-465f-a622-b7ca4237f436', NULL, 'hard', NULL, NULL, '{"en": "A man pushes his car up to a hotel and immediately announces he is bankrupt. Why?", "kz": "Бір адам көлігін қонақүйге дейін итеріп әкеліп, бірден банкрот екенін айтады. Неліктен?"}', '[{"en": "His car broke down", "kz": "Көлігі бұзылған"}, {"en": "He is playing Monopoly", "kz": "Ол «Монополия» ойнап жатыр"}, {"en": "He lost his wallet", "kz": "Әмиянын жоғалтқан"}, {"en": "The hotel is too expensive", "kz": "Қонақүй тым қымбат"}]', 1, '🎩', NULL, 300, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('4338f2e6-a93e-4569-b537-e576e90e5061', NULL, 'hard', NULL, NULL, '{"en": "You have 9 identical-looking coins; exactly one is slightly heavier. Using only a balance scale, what is the minimum number of weighings that guarantees finding it?", "kz": "Сізде 9 бірдей көрінетін монета бар; нақ біреуі сәл ауырлау. Тек теңгерме таразымен оны табуға кепілдік беретін ең аз өлшеу саны қанша?"}', '[{"en": "1", "kz": "1"}, {"en": "2", "kz": "2"}, {"en": "3", "kz": "3"}, {"en": "4", "kz": "4"}]', 1, '⚖️', NULL, 300, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('335ae29f-e5f9-4a4d-9c4b-dacd1ae7c7b0', NULL, 'hard', NULL, NULL, '{"en": "Two fathers and two sons go fishing. Each catches exactly one fish, yet only three fish are caught in total. How?", "kz": "Екі әке мен екі ұл балық аулауға барды. Әрқайсысы нақ бір балық ұстады, бірақ бәрі болып үш-ақ балық ұсталды. Қалай?"}', '[{"en": "One fish escaped", "kz": "Бір балық қашып кетті"}, {"en": "They miscounted", "kz": "Қате санаған"}, {"en": "They are a grandfather, a father, and a son", "kz": "Олар — ата, әке және ұл"}, {"en": "One of them caught two", "kz": "Біреуі екеуін ұстады"}]', 2, '🎣', NULL, 300, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('e300863e-95b9-43d8-8d3d-c4cb6d6ba753', NULL, 'hard', NULL, NULL, '{"en": "All of Anna''s friends speak French. Some people who speak French are teachers. Which statement MUST be true?", "kz": "Аннаның барлық достары француз тілінде сөйлейді. Француз тілінде сөйлейтін кейбіреулер — мұғалім. Қай тұжырым МІНДЕТТІ ТҮРДЕ ақиқат?"}', '[{"en": "Some of Anna''s friends are teachers", "kz": "Аннаның кейбір достары — мұғалім"}, {"en": "None of Anna''s friends are teachers", "kz": "Аннаның бірде-бір досы мұғалім емес"}, {"en": "Nothing certain can be concluded about that", "kz": "Бұл туралы нақты қорытынды жасауға болмайды"}, {"en": "All of Anna''s friends are teachers", "kz": "Аннаның барлық достары — мұғалім"}]', 2, '🧑‍🏫', NULL, 300, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('ece59574-11f2-4872-aca1-85ecc31fb818', NULL, 'hard', NULL, NULL, '{"en": "A woman shoots her husband, holds him under water for several minutes, then hangs him. An hour later they have dinner together. How?", "kz": "Бір әйел күйеуін атып, бірнеше минут су астында ұстайды, сосын іліп қояды. Бір сағаттан соң олар бірге кешкі ас ішеді. Қалай?"}', '[{"en": "She is a photographer", "kz": "Ол — фотограф"}, {"en": "He is a ghost", "kz": "Күйеуі — елес"}, {"en": "It was only a dream", "kz": "Бұл жай түс еді"}, {"en": "He has a twin brother", "kz": "Күйеуінің егіз ағасы бар"}]', 0, '📷', NULL, 300, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('fa0fd8ce-2173-4466-816d-07fd57850ee4', NULL, 'hard', NULL, NULL, '{"en": "You flip a fair coin three times. Given that at least one flip is heads, what is the probability that all three are heads?", "kz": "Әділ тиынды үш рет лақтырдыңыз. Кемінде бір рет «бүркіт» түскені белгілі болса, үшеуінің де «бүркіт» болу ықтималдығы қанша?"}', '[{"en": "1/8", "kz": "1/8"}, {"en": "1/7", "kz": "1/7"}, {"en": "1/3", "kz": "1/3"}, {"en": "1/2", "kz": "1/2"}]', 1, '🪙', NULL, 300, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('223edc57-d46d-41da-9e26-772eeaf6781e', NULL, 'hard', NULL, NULL, '{"en": "Two doors: one leads to safety, one to death. One guard always lies, the other always tells the truth, but you don''t know which is which. You may ask ONE guard ONE yes/no question. Which approach works?", "kz": "Екі есік: біреуі — қауіпсіздікке, біреуі — өлімге. Бір күзетші әрқашан өтірік, екіншісі әрқашан шындық айтады, бірақ қайсысы екенін білмейсіз. Бір күзетшіге бір «иә/жоқ» сұрақ қоя аласыз. Қай тәсіл жұмыс істейді?"}', '[{"en": "Ask ''Are you the truth-teller?''", "kz": "«Сіз шындық айтушысыз ба?» деп сұраңыз"}, {"en": "Ask ''Which door would the OTHER guard call safe?'' then pick the other door", "kz": "«Екінші күзетші қай есікті қауіпсіз дер еді?» деп сұрап, басқа есікті таңдаңыз"}, {"en": "Ask ''Is the left door safe?''", "kz": "«Сол жақ есік қауіпсіз бе?» деп сұраңыз"}, {"en": "Ask ''Which door is safe?''", "kz": "«Қай есік қауіпсіз?» деп сұраңыз"}]', 1, '🚪', NULL, 300, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('00b937d4-e6ac-4006-993d-805e057321b3', NULL, 'hard', NULL, NULL, '{"en": "''If it rains, the match is cancelled. The match was cancelled. Therefore it rained.'' This argument is:", "kz": "«Егер жаңбыр жауса, матч болмай қалады. Матч болмай қалды. Демек, жаңбыр жауды.» Бұл пайымдау:"}', '[{"en": "Valid", "kz": "Дұрыс (валид)"}, {"en": "Invalid — the match could be cancelled for other reasons", "kz": "Қате — матч басқа себептермен де болмай қалуы мүмкін"}, {"en": "True by definition", "kz": "Анықтама бойынша ақиқат"}, {"en": "Impossible to judge", "kz": "Бағалау мүмкін емес"}]', 1, '🌧️', NULL, 300, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('f8e8d4ed-6515-4900-bbe3-0b245c015b82', NULL, 'hard', NULL, NULL, '{"en": "Sara is looking at John. John is looking at Mary. Sara is married; Mary is not. We don''t know if John is married. Is a married person looking at an unmarried person?", "kz": "Сара Джонға қарап тұр. Джон Мэриге қарап тұр. Сара — үйленген; Мэри — үйленбеген. Джон туралы белгісіз. Үйленген адам үйленбеген адамға қарап тұр ма?"}', '[{"en": "Yes", "kz": "Иә"}, {"en": "No", "kz": "Жоқ"}, {"en": "Not enough information", "kz": "Ақпарат жеткіліксіз"}, {"en": "Only if John is married", "kz": "Тек Джон үйленген болса"}]', 0, '💍', NULL, 300, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('5ae12d1f-95ed-4498-b713-761e21f77b13', NULL, 'hard', NULL, NULL, '{"en": "A bag holds 2 red and 2 blue balls. You draw two at once without looking. What is the probability both are the same color?", "kz": "Қапта 2 қызыл және 2 көк шар бар. Қарамай бірден екеуін аласыз. Екеуінің түсі бірдей болу ықтималдығы қанша?"}', '[{"en": "1/2", "kz": "1/2"}, {"en": "1/3", "kz": "1/3"}, {"en": "1/4", "kz": "1/4"}, {"en": "2/3", "kz": "2/3"}]', 1, '🎱', NULL, 300, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('20ce9ed0-1b97-4443-8720-d3ad8cd14913', NULL, 'hard', NULL, NULL, '{"en": "In a running race, if you overtake the person in last place, what position are you then in?", "kz": "Жүгіру жарысында ең соңғы орындағы адамды басып озсаңыз, сіз қай орында боласыз?"}', '[{"en": "Last", "kz": "Соңғы"}, {"en": "Second to last", "kz": "Соңынан екінші"}, {"en": "You can''t overtake the last-place person", "kz": "Ең соңғы адамды басып озу мүмкін емес"}, {"en": "First", "kz": "Бірінші"}]', 2, '🏁', NULL, 300, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('e12c60f3-de07-43ff-8c35-a667d78ace36', NULL, 'hard', NULL, NULL, '{"en": "A man is found hanging in a sealed, empty, locked room with a puddle of water beneath him and no furniture. How did he do it?", "kz": "Бір ер адам жабық, бос, кілттелген бөлмеде асылып тұрған күйде табылды; астында су көлшігі бар, жиһаз жоқ. Ол мұны қалай істеді?"}', '[{"en": "He climbed the walls", "kz": "Қабырғаға өрмелеп шықты"}, {"en": "He stood on a large block of ice that then melted", "kz": "Ірі мұз кесегінің үстіне тұрды, ол кейін еріп кетті"}, {"en": "Someone helped him", "kz": "Біреу көмектесті"}, {"en": "There was a hidden ladder", "kz": "Жасырын саты болған"}]', 1, '🧊', NULL, 300, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('07a017c5-e80f-4963-826b-ed84e26920af', NULL, 'hard', NULL, NULL, '{"en": "A company reports ''90% of customers are satisfied,'' but only 10% of customers chose to return the survey. The biggest flaw in this claim is:", "kz": "Бір компания «тұтынушылардың 90%-ы риза» дейді, бірақ сауалнаманы тұтынушылардың тек 10%-ы қайтарған. Бұл тұжырымдағы ең басты қате:"}', '[{"en": "The sample is too small", "kz": "Таңдама тым кішкентай"}, {"en": "Self-selection bias — unhappy customers may not respond", "kz": "Өзін-өзі іріктеу ауытқуы — ренжігендер жауап бермеуі мүмкін"}, {"en": "90% is not a majority", "kz": "90% — көпшілік емес"}, {"en": "There is no flaw", "kz": "Ешқандай қате жоқ"}]', 1, '📊', NULL, 300, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('17922466-7c3b-4c78-88eb-98c7df2f77b8', NULL, 'hard', NULL, NULL, '{"en": "All cats are mammals. No mammals are reptiles. Which conclusion is logically valid?", "kz": "Барлық мысықтар — сүтқоректілер. Бірде-бір сүтқоректі бауырымен жорғалаушы емес. Қай қорытынды дұрыс?"}', '[{"en": "Some cats are reptiles", "kz": "Кейбір мысықтар — бауырымен жорғалаушы"}, {"en": "No cats are reptiles", "kz": "Бірде-бір мысық бауырымен жорғалаушы емес"}, {"en": "All mammals are cats", "kz": "Барлық сүтқоректілер — мысық"}, {"en": "Some reptiles are cats", "kz": "Кейбір бауырымен жорғалаушылар — мысық"}]', 1, '🐱', NULL, 300, 100, true, '2026-06-05 10:02:30.694241');
INSERT INTO public.questions (id, quiz_id, difficulty, category, "order", prompt, choices, correct_index, icon, explanation, time_limit, points, is_active, created_at) VALUES ('83a2ddd1-29d0-44f7-98e1-ead3366793f5', NULL, 'hard', NULL, NULL, '{"en": "Ice-cream sales and drowning deaths rise and fall together over the year. What is the best explanation?", "kz": "Балмұздақ сатылымы мен суға кету оқиғалары жыл бойы бірге өсіп, бірге азаяды. Ең дұрыс түсіндірме қандай?"}', '[{"en": "Ice cream causes drowning", "kz": "Балмұздақ суға кетуге себеп болады"}, {"en": "Drowning drives ice-cream sales", "kz": "Суға кету балмұздақ сатылымын арттырады"}, {"en": "A third factor — hot weather — drives both", "kz": "Үшінші фактор — ыстық ауа райы — екеуіне де әсер етеді"}, {"en": "It is pure coincidence", "kz": "Бұл — таза кездейсоқтық"}]', 2, '🍦', NULL, 300, 100, true, '2026-06-05 10:02:30.694241');
